import React, { useState } from 'react';
import { 
  MagnifyingGlassIcon,
  FunnelIcon,
  UserGroupIcon,
  UserPlusIcon
} from '@heroicons/react/24/outline';

const ActionBar = () => {
  const [searchTerm, setSearchTerm] = useState('');

  return (
    <div className="w-fit bg-neutral-800 rounded-lg h-20 p-4 flex items-center space-x-3">
      {/* Search Input */}
      <div className="relative">
        <input
          type="text"
          placeholder="Search..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="w-48 bg-neutral-700 border border-neutral-600 rounded-lg px-4 py-2 pl-10 text-white placeholder-neutral-400 focus:outline-none focus:ring-2 focus:ring-white focus:border-transparent text-sm"
        />
        <MagnifyingGlassIcon className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-neutral-400" />
      </div>

      {/* Sort Button */}
      <button className="flex items-center space-x-2 px-4 py-2 bg-neutral-700 hover:bg-neutral-600 border border-neutral-600 rounded-lg transition-colors">
        <FunnelIcon className="h-4 w-4 text-neutral-300" />
        <span className="text-neutral-300 text-sm font-medium">Sort</span>
      </button>

      {/* Create Group Button */}
      <button className="flex items-center space-x-2 px-4 py-2 bg-neutral-700 hover:bg-neutral-600 border border-neutral-600 rounded-lg transition-colors">
        <UserGroupIcon className="h-4 w-4 text-neutral-300" />
        <span className="text-neutral-300 text-sm font-medium">Create group</span>
      </button>

      {/* Invite Button */}
      <button className="flex items-center space-x-2 px-4 py-2 bg-white hover:bg-gray-100 rounded-lg transition-colors">
        <UserPlusIcon className="h-4 w-4 text-black" />
        <span className="text-black text-sm font-medium">Invite</span>
      </button>
    </div>
  );
};

export default ActionBar;
